            result.Add(new NodePropSpec(openedByProp, new object[] { 23, "(", 31, "[", 34, "{" }));
        }
        if (nodeProps.TryGetValue("closedBy", out var closedByProp))
        {
            result.Add(new NodePropSpec(closedByProp, new object[] { 24, ")", 32, "]", 35, "}" }));
        }
        return result.Count > 0 ? result.ToArray() : null;
